<?php
declare(strict_types=1);require_once __DIR__.'/../app/email_marketing.php';proteger_admin();$pdo=getPDO();email_marketing_ensure_schema($pdo);$id=max(1,(int)($_GET['id']??$_POST['id']??0));$csrf=email_admin_csrf();$error=$message='';$st=$pdo->prepare('SELECT * FROM email_flows WHERE id=:id');$st->execute(['id'=>$id]);$flow=$st->fetch(PDO::FETCH_ASSOC);if(!$flow){http_response_code(404);exit('Automação não encontrada.');}if($_SERVER['REQUEST_METHOD']==='POST')try{email_check_csrf();$name=trim((string)$_POST['name']);$description=trim((string)$_POST['description']);$graph=json_decode((string)$_POST['graph_json'],true,512,JSON_THROW_ON_ERROR);if($name===''||!isset($graph['nodes'],$graph['edges'])||count($graph['nodes'])>200)throw new InvalidArgumentException('Fluxo inválido.');$publish=($_POST['action']??'save')==='publish';$pdo->beginTransaction();$pdo->prepare('UPDATE email_flows SET name=:n,description=:d,draft_graph_json=:g WHERE id=:id')->execute(['n'=>$name,'d'=>$description?:null,'g'=>json_encode($graph,JSON_UNESCAPED_UNICODE),'id'=>$id]);if($publish){$st=$pdo->prepare('SELECT COALESCE(MAX(version_number),0)+1 FROM email_flow_versions WHERE flow_id=:id');$st->execute(['id'=>$id]);$v=(int)$st->fetchColumn();$pdo->prepare('INSERT INTO email_flow_versions(flow_id,version_number,graph_json,created_by) VALUES(:f,:v,:g,:a)')->execute(['f'=>$id,'v'=>$v,'g'=>json_encode($graph,JSON_UNESCAPED_UNICODE),'a'=>$_SESSION['equipe_nome']??'Administrador']);$vid=(int)$pdo->lastInsertId();$pdo->prepare("UPDATE email_flows SET current_version_id=:v,status='active' WHERE id=:id")->execute(['v'=>$vid,'id'=>$id]);}$pdo->commit();header('Location: email_fluxo.php?id='.$id.'&saved=1');exit;}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();$error=$e->getMessage();}$templates=$pdo->query("SELECT v.id,CONCAT(t.name,' · v',v.version_number) label FROM email_templates t JOIN email_template_versions v ON v.id=t.current_version_id ORDER BY t.name")->fetchAll(PDO::FETCH_ASSOC)?:[];$menu='email_marketing';$page_title='Editor de automação';include __DIR__.'/_header.php';echo email_admin_styles();?><style>.flow-layout{display:grid;grid-template-columns:190px 1fr 280px;gap:12px}.flow-palette button{width:100%;margin:5px 0;padding:9px;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);text-align:left}.flow-canvas{position:relative;min-height:600px;overflow:auto;background-color:#080e1a;background-image:radial-gradient(#334155 1px,transparent 1px);background-size:20px 20px}.flow-node{position:absolute;width:190px;background:var(--bg-card);border:1px solid var(--border);border-left:4px solid var(--node-color);border-radius:10px;padding:11px;cursor:move}.flow-node.selected{box-shadow:0 0 0 2px var(--primary)}.flow-node small{display:block;color:var(--muted)}@media(max-width:900px){.flow-layout{grid-template-columns:1fr}.flow-canvas{min-height:450px}}</style><div class="em"><div class="em-head"><div><h1>Editor de automação</h1><p class="text-muted">Arraste blocos e configure a jornada.</p></div><a class="btn btn-ghost" href="email_fluxos.php">← Automações</a></div><?=email_admin_nav('flows')?><?php if(isset($_GET['saved'])):?><div class="em-msg">Automação salva.</div><?php endif?><?php if($error):?><div class="em-msg em-error"><?=email_h($error)?></div><?php endif?><form method="post" id="flowForm"><input type="hidden" name="csrf" value="<?=email_h($csrf)?>"><input type="hidden" name="id" value="<?=$id?>"><input type="hidden" name="graph_json" id="graphField"><div class="em-card em-form"><label>Nome<input name="name" value="<?=email_h($flow['name'])?>" required></label><label>Descrição<input name="description" value="<?=email_h($flow['description']??'')?>"></label><div class="em-actions"><button class="btn btn-ghost" name="action" value="save">Salvar rascunho</button><button class="btn btn-primary" name="action" value="publish">Publicar nova versão</button></div></div><div class="flow-layout"><aside class="em-card flow-palette"><h2>Blocos</h2><button type="button" data-type="condition">◇ Condição</button><button type="button" data-type="wait">◷ Espera</button><button type="button" data-type="email">✉ E-mail</button><button type="button" data-type="tag"># Tag</button><button type="button" data-type="integration">↗ Integração</button><button type="button" data-type="end">■ Encerrar</button></aside><main class="flow-canvas" id="canvas"></main><aside class="em-card em-form" id="inspector"><h2>Configuração</h2><p class="text-muted">Selecione um bloco.</p></aside></div></form></div><script>(()=>{const graph=<?=json_encode(json_decode($flow['draft_graph_json'],true),JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>,canvas=document.getElementById('canvas'),inspector=document.getElementById('inspector');let selected=null,drag=null;const meta={trigger:['Gatilho','#38bdf8'],condition:['Condição','#22c55e'],wait:['Espera','#fb7185'],email:['E-mail','#facc15'],tag:['Tag','#f59e0b'],integration:['Integração','#a78bfa'],end:['Encerrar','#64748b']};function esc(s){return String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}function summary(n){if(n.type==='email')return n.config.templateLabel||'Selecione um modelo';if(n.type==='wait')return (n.config.duration||1)+' '+(n.config.unit||'dias');if(n.type==='condition')return n.config.condition||'Abriu o e-mail anterior?';return n.config.label||meta[n.type][0]}function render(){canvas.innerHTML='';graph.nodes.forEach(n=>{const e=document.createElement('div');e.className='flow-node'+(selected===n.id?' selected':'');e.style.cssText=`left:${n.x}px;top:${n.y}px;--node-color:${meta[n.type][1]}`;e.innerHTML='<strong>'+esc(n.config.label||meta[n.type][0])+'</strong><small>'+esc(summary(n))+'</small>';e.onclick=()=>{selected=n.id;render();inspect()};e.onpointerdown=ev=>{if(ev.button!==0)return;drag={n,dx:ev.clientX-n.x,dy:ev.clientY-n.y};e.setPointerCapture(ev.pointerId)};e.onpointermove=ev=>{if(drag?.n===n){n.x=Math.max(0,ev.clientX-drag.dx);n.y=Math.max(0,ev.clientY-drag.dy);e.style.left=n.x+'px';e.style.top=n.y+'px'}};e.onpointerup=()=>drag=null;canvas.appendChild(e)})}function inspect(){const n=graph.nodes.find(x=>x.id===selected);if(!n){inspector.innerHTML='<h2>Configuração</h2><p>Selecione um bloco.</p>';return}let extra='';if(n.type==='email')extra='<label>Modelo<select id="iTemplate"><option value="">Selecione</option><?=implode('',array_map(fn($t)=>'<option value="'.(int)$t['id'].'">'.email_h($t['label']).'</option>',$templates))?></select></label><a class="btn btn-ghost" href="email_editor.php" target="_blank">Criar novo e-mail</a>';if(n.type==='wait')extra='<label>Duração<input id="iDuration" type="number" min="1" value="'+esc(n.config.duration||1)+'"></label><label>Unidade<select id="iUnit"><option value="minutes">minutos</option><option value="hours">horas</option><option value="days">dias</option></select></label>';if(n.type==='condition')extra='<label>Condição<select id="iCondition"><option>Entregue</option><option>Aberto</option><option>Clicou em qualquer link</option><option>Clicou em link específico</option><option>Não abriu após espera</option><option>Não clicou após espera</option><option>Bounce</option><option>Reclamação</option><option>Descadastrado</option></select></label>';inspector.innerHTML='<h2>'+meta[n.type][0]+'</h2><label>Rótulo<input id="iLabel" value="'+esc(n.config.label||'')+'"></label>'+extra+(n.type!=='trigger'?'<button type="button" class="btn btn-danger" id="removeNode">Excluir bloco</button>':'');iLabel.oninput=()=>{n.config.label=iLabel.value;render()};if(window.iDuration)iDuration.oninput=()=>{n.config.duration=+iDuration.value;render()};if(window.iUnit){iUnit.value=n.config.unit||'days';iUnit.onchange=()=>{n.config.unit=iUnit.value;render()}}if(window.iCondition){iCondition.value=n.config.condition||'Aberto';iCondition.onchange=()=>{n.config.condition=iCondition.value;render()}}if(window.iTemplate){iTemplate.value=n.config.templateVersionId||'';iTemplate.onchange=()=>{n.config.templateVersionId=+iTemplate.value;n.config.templateLabel=iTemplate.options[iTemplate.selectedIndex].text;render()}}if(window.removeNode)removeNode.onclick=()=>{graph.nodes=graph.nodes.filter(x=>x.id!==n.id);selected=null;render();inspect()}}document.querySelectorAll('[data-type]').forEach((b,i)=>b.onclick=()=>{const type=b.dataset.type,n={id:type+'_'+Date.now(),type,x:260+(graph.nodes.length%3)*220,y:70+graph.nodes.length*95,config:{label:meta[type][0]}};graph.nodes.push(n);selected=n.id;render();inspect()});document.getElementById('flowForm').onsubmit=()=>document.getElementById('graphField').value=JSON.stringify(graph);render()})();</script><?php include __DIR__.'/_footer.php';
